import { toServerItemLeaderboardRecordList, } from '../../../../models/server/items/leaderboards/records/list.js';
import { extractString } from '../../../../utils/extract.js';
import { handleError } from '../../../error.js';
export const createServerItemLeaderboardRecordListRouteHandler = (sonolus, group) => async ({ req, res, localize, ctx }) => {
    if (!group.leaderboard.record.listHandler) {
        res.status(404).end();
        return;
    }
    const itemName = req.params.itemName;
    if (!itemName) {
        res.status(400).end();
        return;
    }
    const leaderboardName = req.params.leaderboardName;
    if (!leaderboardName) {
        res.status(400).end();
        return;
    }
    const response = await group.leaderboard.record.listHandler({
        ...ctx,
        itemName,
        leaderboardName,
        page: +(req.query.page ?? '') || 0,
        cursor: extractString(req.query.cursor),
    });
    if (handleError(response, res, localize))
        return;
    res.json(toServerItemLeaderboardRecordList(sonolus, localize, response));
};
